    "id": "PresetFilter",
    "args": ["component", "value"]
});

filterBc.attachToComponentValue(
    [SearchField, TagList, FavoriteToggle],
    "filterInputs"
);

var rebuildCount = 0;

// The delayed listener fires only after 30ms of inactivity.
