// Context: When a sampler has limited samples in the upper register,
// multiple notes can share the same sample with slight per-note detuning
// to avoid the "machine gun" effect. A deterministic pseudo-random table
// ensures consistent results across plays.

const var SHARED_RANGE_LOW = 50;
const var SHARED_RANGE_HIGH = 90;

// Build a deterministic pseudo-random detune table
const var detuneTable = [];

for (i = 0; i < 128; i++)
    detuneTable.push(parseInt(Math.sin(i * 925512.2934) * 100.0));

function onNoteOn()
{
    local note = Message.getNoteNumber();

    if (note >= SHARED_RANGE_LOW && note <= SHARED_RANGE_HIGH)
    {
        // Map multiple notes to the same sample via transpose
        local sampleNote = SHARED_RANGE_LOW + (note - SHARED_RANGE_LOW) % 2;

        Message.setTransposeAmount(sampleNote - note);

        // Add pseudo-random fine detuning for natural variation
        Message.setFineDetune(detuneTable[note]);
    }
}

// Context: An additive synthesis instrument uses setStartOffset to start
// each harmonic oscillator at a different phase position per note,
// creating organic key-click and attack variation. The phase angle
// is converted from radians to a sample offset within a single
// wavetable cycle.

const var CYCLE_LENGTH = 2048; // Samples per wavetable cycle

// Pre-computed phase offsets per MIDI note (radians)
const var phaseTable = [];

for (i = 0; i < 128; i++)
    phaseTable.push(Math.sin(i * 1.7) * Math.PI); // Pseudo-random distribution

function onNoteOn()
{
    local note = Message.getNoteNumber();

    // Convert phase angle (radians) to sample offset within one cycle
    local phaseDeg = Math.toDegrees(phaseTable[note] + (2 * Math.PI));
    local offset = parseInt(phaseDeg / 360 * CYCLE_LENGTH);

    Message.setStartOffset(offset);
}

// Context: In a sampled instrument, shifting which sample is triggered
// changes the timbre (brighter/darker) without changing the heard pitch.
// setTransposeAmount selects a different sample zone, while setCoarseDetune
// with the opposite sign cancels the pitch change.

const var timbreKnob = Content.addKnob("Timbre", 10, 10);
timbreKnob.setRange(-12, 12, 1);

function onNoteOn()
{
    local amount = parseInt(timbreKnob.getValue());

    // Transpose selects a different sample zone
    Message.setTransposeAmount(-amount);

    // Coarse detune cancels the pitch shift so the note sounds at the original pitch
    Message.setCoarseDetune(amount);
}

// Context: A piano plugin shifts timbre by a variable amount, clamping
// to the instrument's sample range so extreme values don't go out of bounds.

const var timbreKnob = Content.addKnob("Timbre", 10, 10);
timbreKnob.setRange(0, 4, 1);

const var NOTE_LOW = 21;   // Lowest sampled note (A0)
const var NOTE_HIGH = 108; // Highest sampled note (C8)

function onNoteOn()
{
    local amount = parseInt(timbreKnob.getValue()) * 2;

    // Clamp so the transposed note stays within the sample range
    local targetNote = Math.range(Message.getNoteNumber() - amount, NOTE_LOW, NOTE_HIGH);
    local actualShift = Message.getNoteNumber() - targetNote;

    Message.setTransposeAmount(-actualShift);
    Message.setCoarseDetune(actualShift);
}

// Context: A velocity table modifies the incoming velocity to match
// the instrument's dynamic response. The table provides a normalized
// curve (0.0-1.0 input/output) that reshapes the velocity distribution.

const var veloTable = Content.addTable("VeloTable", 10, 10);
veloTable.set("height", 200);
veloTable.set("width", 400);

const var table = veloTable.registerAtParent(0);

function onNoteOn()
{
    // Map velocity through the table curve
    local v = 127.0 * table.getTableValueNormalised(Message.getVelocity() / 127.0);

    Message.setVelocity(parseInt(Math.max(1, v)));
}

// Context: A sampler that plays release samples when notes are released.
// store() copies the note-on event into a MessageHolder for later replay
// as a release trigger. An UnorderedStack tracks all held notes.

const var holder = Engine.createMessageHolder();
const var stack = Engine.createUnorderedStack();
stack.setIsEventStack(true, stack.EventId);

const var uptimes = [];
uptimes.reserve(128);

for (i = 0; i < 128; i++)
    uptimes[i] = 0.0;

// Register a callback to clear state when all notes are released
inline function onAllOff()
{
    stack.clear();

    for (i = 0; i < 128; i++)
        uptimes[i] = 0.0;
}

Message.setAllNotesOffCallback(onAllOff);

inline function handleNoteOn()
{
    // Store the current event for later release triggering
    Message.store(holder);
    stack.insert(holder);
    uptimes[Message.getNoteNumber()] = Engine.getUptime();

    // Suppress the note-on from this sampler (it plays release samples only)
    Message.ignoreEvent(true);
}

