// Context: Register an async (UI-thread) callback to update transport button
// state and handle recording transitions. Use the async mode (0) since
// the callback updates UI components.

const var mp = Synth.getMidiPlayer("MidiPlayer1");
mp.create(4, 4, 1);

reg isRecording = false;
reg lastState = -1;

inline function onPlaybackChange(timestamp, playState)
{
    lastState = playState;

    // playState: 0 = stop, 1 = play, 2 = record
    if (playState == 2 && !isRecording)
    {
        // Just entered recording
        isRecording = true;
    }

    if (playState != 2 && isRecording)
    {
        // Recording just stopped - sequence data was flushed automatically
        isRecording = false;
    }
}

// Pass 0 for async (UI thread) - safe for component updates
mp.setPlaybackCallback(onPlaybackChange, 0);

// Context: A record event callback that filters out notes not matching the
// current channel and quantizes timestamps to the grid. This runs on the
// audio thread so it must be an inline function.

const var mp = Synth.getMidiPlayer("MidiPlayer1");
mp.setUseTimestampInTicks(true);

const var CHANNEL_NOTE = 36; // The note number this channel responds to

inline function onRecordEvent(e)
{
    if (e.isNoteOn())
    {
        local number = e.getNoteNumber();

        // Filter out notes that don't belong to this channel
        if (number != CHANNEL_NOTE)
        {
            e.ignoreEvent(true);
            return;
        }

        // Quantize to 16th note grid
        local tpq = mp.getTicksPerQuarter(); // 960
        local gridSize = tpq / 4;            // 240 ticks = 16th note
        local ts = e.getTimestamp();
        local quantised = Math.round(ts / gridSize) * gridSize;
        e.setTimestamp(quantised);
    }
}

mp.setRecordEventCallback(onRecordEvent);

// Context: Register a callback that fires when the MIDI data changes
// (load, edit, clear). Use this to rebuild UI elements like step
// sequencer displays. The callback fires once immediately on registration.

const var mp = Synth.getMidiPlayer("MidiPlayer1");

reg callbackCount = 0;

inline function onSequenceChange(player)
{
    callbackCount++;

    // Rebuild the step sequencer UI from the new MIDI data
    if (!player.isEmpty())
    {
        var ts = player.getTimeSignature();
        Console.print("Sequence changed: " + ts.NumBars + " bars, " +
                       ts.Nominator + "/" + ts.Denominator);
    }
}

mp.setSequenceCallback(onSequenceChange);
